import itertools

class Solution:
    def maxDistinct(self, s):
        n = len(s)
        best = 0
        positions = list(range(1, n))
        for r in range(len(positions) + 1):
            for combo in itertools.combinations(positions, r):
                cuts = [0] + list(combo) + [n]
                starts = [s[cuts[i]] for i in range(len(cuts) - 1)]
                if len(set(starts)) == len(starts) and len(starts) > best:
                    best = len(starts)
        return best

